package genxsolution.vms.vmsbackend.employee_hr_management.ration_distribution.service;
import genxsolution.vms.vmsbackend.employee_hr_management.exception.HrResourceNotFoundException; import genxsolution.vms.vmsbackend.employee_hr_management.ration_distribution.dto.*; import genxsolution.vms.vmsbackend.employee_hr_management.ration_distribution.mapper.RationDistributionMapper; import genxsolution.vms.vmsbackend.employee_hr_management.ration_distribution.repository.RationDistributionRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class RationDistributionService { private final RationDistributionRepository repository; private final RationDistributionMapper mapper; public RationDistributionService(RationDistributionRepository repository,RationDistributionMapper mapper){this.repository=repository;this.mapper=mapper;} public List<RationDistributionResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public RationDistributionResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new HrResourceNotFoundException("RationDistribution", id.toString())); } public RationDistributionResponse create(RationDistributionUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public RationDistributionResponse update(UUID id,RationDistributionUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new HrResourceNotFoundException("RationDistribution", id.toString())); } public void delete(UUID id){ if(!repository.delete(id)) throw new HrResourceNotFoundException("RationDistribution", id.toString()); } }
